CREATE
VIEW q_v_object_list
AS
SELECT
  `o`.`IDob` AS `IDob`,
  `o`.`obCode` AS `obCode`,
  `o`.`obName` AS `obName`,
  `os`.`osName` AS `osName`,
  `o`.`obPrice` AS `obPrice`,
  `sns`.`snsRegion` AS `snsRegion`,
  `sns`.`snsDistrict` AS `snsDistrict`,
  `sns`.`snsName` AS `snsName`,
  `sp`.`spStreet` AS `spStreet`,
  `sp`.`spPlotNo` AS `spPlotNo`,
  CONCAT(IFNULL(CONCAT(`sns`.`snsName`, ', '), ''), IFNULL(CONCAT(`sp`.`spStreet`, ', '), ''), IFNULL(CONCAT('уч. ', NULLIF(`sp`.`spPlotNo`, '')), '')) AS `obShortAddress`
FROM (((`object` `o`
  JOIN `object_status` `os`
    ON ((`os`.`IDos` = `o`.`obStatusID`)))
  JOIN `snt_place` `sp`
    ON ((`sp`.`IDsp` = `o`.`obPlaceID`)))
  JOIN `snt_settlement` `sns`
    ON ((`sns`.`IDsns` = `sp`.`spSettlementID`)));

CREATE
VIEW q_v_rep_obj_group_snt_status
AS
SELECT
  TRIM(`q_v_object_list`.`snsName`) AS `snt_name`,
  TRIM(`q_v_object_list`.`osName`) AS `status_name`,
  COUNT(0) AS `cnt_objects`,
  MIN(`q_v_object_list`.`obPrice`) AS `price_min`,
  MAX(`q_v_object_list`.`obPrice`) AS `price_max`,
  AVG(`q_v_object_list`.`obPrice`) AS `price_avg`
FROM `q_v_object_list`
GROUP BY TRIM(`q_v_object_list`.`snsName`),
         TRIM(`q_v_object_list`.`osName`)
ORDER BY `snt_name`, `status_name`;

CREATE
VIEW q_v_rep_object_master
AS
SELECT
  `q_v_object_list`.`IDob` AS `IDob`,
  `q_v_object_list`.`obCode` AS `obCode`,
  `q_v_object_list`.`obName` AS `obName`,
  `q_v_object_list`.`osName` AS `osName`,
  `q_v_object_list`.`obPrice` AS `obPrice`,
  `q_v_object_list`.`snsRegion` AS `snsRegion`,
  `q_v_object_list`.`snsDistrict` AS `snsDistrict`,
  `q_v_object_list`.`snsName` AS `snsName`,
  `q_v_object_list`.`spStreet` AS `spStreet`,
  `q_v_object_list`.`spPlotNo` AS `spPlotNo`,
  `q_v_object_list`.`obShortAddress` AS `obShortAddress`
FROM `q_v_object_list`;

CREATE
VIEW q_v_rep_object_list
AS
SELECT
  `q_v_object_list`.`IDob` AS `IDob`,
  `q_v_object_list`.`obCode` AS `obCode`,
  `q_v_object_list`.`obName` AS `obName`,
  `q_v_object_list`.`osName` AS `osName`,
  `q_v_object_list`.`obPrice` AS `obPrice`,
  `q_v_object_list`.`snsRegion` AS `snsRegion`,
  `q_v_object_list`.`snsDistrict` AS `snsDistrict`,
  `q_v_object_list`.`snsName` AS `snsName`,
  `q_v_object_list`.`spStreet` AS `spStreet`,
  `q_v_object_list`.`spPlotNo` AS `spPlotNo`,
  `q_v_object_list`.`obShortAddress` AS `obShortAddress`
FROM `q_v_object_list`;

CREATE
VIEW q_v_chart_status_structure
AS
SELECT
  TRIM(`q_v_object_list`.`osName`) AS `status_name`,
  COUNT(0) AS `cnt_objects`
FROM `q_v_object_list`
GROUP BY TRIM(`q_v_object_list`.`osName`)
ORDER BY `cnt_objects` DESC, `status_name`;

CREATE
VIEW q_v_chart_avg_price_by_snt
AS
SELECT
  TRIM(`q_v_object_list`.`snsName`) AS `snt_name`,
  COUNT(0) AS `cnt_objects`,
  AVG(`q_v_object_list`.`obPrice`) AS `avg_price`,
  MIN(`q_v_object_list`.`obPrice`) AS `price_min`,
  MAX(`q_v_object_list`.`obPrice`) AS `price_max`
FROM `q_v_object_list`
GROUP BY TRIM(`q_v_object_list`.`snsName`)
ORDER BY `avg_price` DESC, `snt_name`;

CREATE TABLE object_photo (
  IDph int(11) NOT NULL AUTO_INCREMENT COMMENT 'Код фото',
  phObjectID int(11) NOT NULL COMMENT 'Объект (FK)',
  phPath varchar(255) DEFAULT NULL COMMENT 'Путь/имя файла фото',
  phIsMain tinyint(1) NOT NULL DEFAULT 0,
  phBlob longblob DEFAULT NULL,
  phFileName varchar(255) DEFAULT NULL,
  phMime varchar(64) DEFAULT NULL,
  phSize int(10) UNSIGNED DEFAULT NULL,
  phUploadedAt datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  phNote varchar(255) DEFAULT NULL COMMENT 'Примечание',
  phMainObjectID int(11) GENERATED ALWAYS AS (CASE WHEN (`phIsMain` = 1) THEN `phObjectID` ELSE NULL END) STORED,
  PRIMARY KEY (IDph)
)
ENGINE = INNODB,
AUTO_INCREMENT = 17,
AVG_ROW_LENGTH = 32768,
CHARACTER SET utf8mb4,
COLLATE utf8mb4_general_ci,
ROW_FORMAT = DYNAMIC;

