REFERENCES object (IDob) ON DELETE CASCADE ON UPDATE CASCADE;

CREATE
VIEW q_v_object_photo_blob
AS
SELECT
  `object_photo`.`IDph` AS `IDph`,
  `object_photo`.`phObjectID` AS `phObjectID`,
  `object_photo`.`phIsMain` AS `phIsMain`,
  COALESCE(NULLIF(`object_photo`.`phFileName`, ''), SUBSTRING_INDEX (`object_photo`.`phPath`, '/', -(1))) AS `phFileName`,
  COALESCE(`object_photo`.`phMime`, (CASE LOWER(SUBSTRING_INDEX (COALESCE(NULLIF(`object_photo`.`phFileName`, ''), `object_photo`.`phPath`), '.', -(1))) WHEN 'jpg' THEN 'image/jpeg' WHEN 'jpeg' THEN 'image/jpeg' WHEN 'png' THEN 'image/png' WHEN 'gif' THEN 'image/gif' WHEN 'bmp' THEN 'image/bmp' WHEN 'webp' THEN 'image/webp' ELSE NULL END)) AS `phMime`,
  `object_photo`.`phSize` AS `phSize`,
  `object_photo`.`phUploadedAt` AS `phUploadedAt`,
  `object_photo`.`phBlob` AS `phBlob`
FROM `object_photo`;

