DELIMITER $$

CREATE
PROCEDURE sp_recalc_object_status (IN p_object_id int)
proc:
  BEGIN
    DECLARE v_free_obj int;
    DECLARE v_booked_obj int;
    DECLARE v_sold_obj int;
    DECLARE v_off_obj int;
    DECLARE v_active_con int;
    DECLARE v_closed_con int;
    DECLARE v_has_closed int DEFAULT 0;
    DECLARE v_has_active int DEFAULT 0;
    DECLARE v_cur_status int DEFAULT NULL;

    SELECT
      IDos INTO v_free_obj
    FROM object_status
    WHERE osName = 'Свободен'
    LIMIT 1;

    SELECT
      IDos INTO v_booked_obj
    FROM object_status
    WHERE osName = 'Бронь'
    LIMIT 1;

    SELECT
      IDos INTO v_sold_obj
    FROM object_status
    WHERE osName = 'Продан'
    LIMIT 1;

    SELECT
      IDos INTO v_off_obj
    FROM object_status
    WHERE osName = 'Снят с продажи'
    LIMIT 1;

    SELECT
      IDcs INTO v_active_con
    FROM contract_status
    WHERE csName = 'Active'
    LIMIT 1;

    SELECT
      IDcs INTO v_closed_con
    FROM contract_status
    WHERE csName = 'Closed'
    LIMIT 1;

    IF v_free_obj IS NULL
      OR v_booked_obj IS NULL
      OR v_sold_obj IS NULL
      OR v_off_obj IS NULL THEN
      SIGNAL SQLSTATE '45000'
      SET MESSAGE_TEXT = 'Не найдены обязательные статусы объекта.';
    END IF;

    IF v_active_con IS NULL
      OR v_closed_con IS NULL THEN
      SIGNAL SQLSTATE '45000'
      SET MESSAGE_TEXT = 'Не найдены обязательные статусы договора.';
    END IF;

    SELECT
      obStatusID INTO v_cur_status
    FROM object
    WHERE IDob = p_object_id
    LIMIT 1;

    IF v_cur_status IS NULL THEN
      SIGNAL SQLSTATE '45000'
      SET MESSAGE_TEXT = 'Объект не найден (IDob).';
    END IF;

    SELECT
      COUNT(*) INTO v_has_closed
    FROM contract
    WHERE conObjectID = p_object_id
    AND conStatusID = v_closed_con;

    SELECT
      COUNT(*) INTO v_has_active
    FROM contract
    WHERE conObjectID = p_object_id
    AND conStatusID = v_active_con;

    IF v_has_closed > 0
      AND v_has_active > 0 THEN
      SIGNAL SQLSTATE '45000'
      SET MESSAGE_TEXT = 'Недопустимое состояние: для объекта одновременно есть Active и Closed договоры.';
    END IF;

    IF v_cur_status = v_off_obj
      AND v_has_closed = 0
      AND v_has_active = 0 THEN
      LEAVE proc;
    END IF;

    IF v_has_active > 0 THEN
      UPDATE object
      SET obStatusID = v_booked_obj,
          obUpdatedAt = NOW()
      WHERE IDob = p_object_id;
    ELSEIF v_has_closed > 0 THEN
      UPDATE object
      SET obStatusID = v_sold_obj,
          obUpdatedAt = NOW()
      WHERE IDob = p_object_id;
    ELSE
      UPDATE object
      SET obStatusID = v_free_obj,
          obUpdatedAt = NOW()
      WHERE IDob = p_object_id;
    END IF;
  END
  $$

DELIMITER ;

CREATE
VIEW q_v_contract_list
AS
SELECT
  `c`.`IDcon` AS `IDcon`,
  `c`.`conNumber` AS `conNumber`,
  `c`.`conDate` AS `conDate`,
  `cs`.`csName` AS `conStatus`,
  `c`.`conStatusID` AS `conStatusID`,
  `c`.`conSum` AS `conSum`,
  `c`.`conPrepay` AS `conPrepay`,
  (`c`.`conSum` - IFNULL(`c`.`conPrepay`, 0)) AS `conDebt`,
  `c`.`conComment` AS `conComment`,
  `cl`.`IDcl` AS `IDcl`,
  `cl`.`clFIO` AS `clFIO`,
  `cl`.`clPhone` AS `clPhone`,
  `cl`.`clEmail` AS `clEmail`,
  `emp`.`IDemp` AS `IDemp`,
  `emp`.`empFIO` AS `empFIO`,
  `emp`.`empPhone` AS `empPhone`,
  `emp`.`empEmail` AS `empEmail`,
  `ep`.`epName` AS `empPosition`,
  `o`.`IDob` AS `IDob`,
  `o`.`obCode` AS `obCode`,
  `o`.`obName` AS `obName`,
  `os`.`osName` AS `osName`,
  `sns`.`snsName` AS `snsName`,
  `sp`.`spStreet` AS `spStreet`,
  `sp`.`spPlotNo` AS `spPlotNo`
FROM ((((((((`contract` `c`
  JOIN `contract_status` `cs`
    ON ((`cs`.`IDcs` = `c`.`conStatusID`)))
  JOIN `client` `cl`
    ON ((`cl`.`IDcl` = `c`.`conClientID`)))
  JOIN `employee` `emp`
    ON ((`emp`.`IDemp` = `c`.`conEmployeeID`)))
  LEFT JOIN `employee_position` `ep`
    ON ((`ep`.`IDep` = `emp`.`empPositionID`)))
  JOIN `object` `o`
    ON ((`o`.`IDob` = `c`.`conObjectID`)))
  JOIN `object_status` `os`
    ON ((`os`.`IDos` = `o`.`obStatusID`)))
  JOIN `snt_place` `sp`
    ON ((`sp`.`IDsp` = `o`.`obPlaceID`)))
  JOIN `snt_settlement` `sns`
    ON ((`sns`.`IDsns` = `sp`.`spSettlementID`)));

CREATE
VIEW q_v_rep_contract_list
AS
SELECT
  `q_v_contract_list`.`IDcon` AS `IDcon`,
  `q_v_contract_list`.`conNumber` AS `conNumber`,
  `q_v_contract_list`.`conDate` AS `conDate`,
  `q_v_contract_list`.`conStatus` AS `conStatus`,
  `q_v_contract_list`.`conStatusID` AS `conStatusID`,
  `q_v_contract_list`.`conSum` AS `conSum`,
  `q_v_contract_list`.`conPrepay` AS `conPrepay`,
  `q_v_contract_list`.`conDebt` AS `conDebt`,
  `q_v_contract_list`.`conComment` AS `conComment`,
  `q_v_contract_list`.`IDcl` AS `IDcl`,
  `q_v_contract_list`.`clFIO` AS `clFIO`,
  `q_v_contract_list`.`clPhone` AS `clPhone`,
  `q_v_contract_list`.`clEmail` AS `clEmail`,
  `q_v_contract_list`.`IDemp` AS `IDemp`,
  `q_v_contract_list`.`empFIO` AS `empFIO`,
  `q_v_contract_list`.`empPhone` AS `empPhone`,
  `q_v_contract_list`.`empEmail` AS `empEmail`,
  `q_v_contract_list`.`empPosition` AS `empPosition`,
  `q_v_contract_list`.`IDob` AS `IDob`,
  `q_v_contract_list`.`obCode` AS `obCode`,
  `q_v_contract_list`.`obName` AS `obName`,
  `q_v_contract_list`.`osName` AS `osName`,
  `q_v_contract_list`.`snsName` AS `snsName`,
  `q_v_contract_list`.`spStreet` AS `spStreet`,
  `q_v_contract_list`.`spPlotNo` AS `spPlotNo`
FROM `q_v_contract_list`;

CREATE
VIEW q_v_rep_contract_group_period
AS
SELECT
  YEAR(`q_v_contract_list`.`conDate`) AS `y`,
  MONTH(`q_v_contract_list`.`conDate`) AS `m`,
  `q_v_contract_list`.`conStatus` AS `conStatus`,
  `q_v_contract_list`.`conStatus` AS `conStatusCode`,
  COUNT(0) AS `cnt_contracts`,
  SUM(`q_v_contract_list`.`conSum`) AS `sum_contracts`
FROM `q_v_contract_list`
GROUP BY YEAR(`q_v_contract_list`.`conDate`),
         MONTH(`q_v_contract_list`.`conDate`),
         `q_v_contract_list`.`conStatus`
ORDER BY `y` DESC, `m` DESC, `q_v_contract_list`.`conStatus`;

CREATE
VIEW q_v_chart_sales_by_month
AS
SELECT
  YEAR(`q_v_contract_list`.`conDate`) AS `y`,
  MONTH(`q_v_contract_list`.`conDate`) AS `m`,
  CONCAT(YEAR(`q_v_contract_list`.`conDate`), '-', LPAD(MONTH(`q_v_contract_list`.`conDate`), 2, '0')) AS `ym`,
  COUNT(0) AS `cnt_contracts`,
  SUM(`q_v_contract_list`.`conSum`) AS `sum_sales`
FROM `q_v_contract_list`
GROUP BY YEAR(`q_v_contract_list`.`conDate`),
         MONTH(`q_v_contract_list`.`conDate`),
         CONCAT(YEAR(`q_v_contract_list`.`conDate`), '-', LPAD(MONTH(`q_v_contract_list`.`conDate`), 2, '0'))
ORDER BY `y`, `m`;

