CREATE
VIEW q_v_global_search
AS
SELECT
  'OBJECT' AS `entity_type`,
  CAST(`q_v_object_list`.`IDob` AS UNSIGNED) AS `entity_id`,
  LEFT(CONCAT_WS(' ', `q_v_object_list`.`obCode`, `q_v_object_list`.`obName`), 255) AS `title`,
  LEFT(CONCAT_WS(' | ', `q_v_object_list`.`osName`, `q_v_object_list`.`snsName`), 255) AS `subtitle`,
  UPPER(TRIM(CONCAT_WS(' ', `q_v_object_list`.`obCode`, `q_v_object_list`.`obName`, `q_v_object_list`.`osName`, `q_v_object_list`.`snsName`))) AS `search_text`
FROM `q_v_object_list`
UNION ALL
SELECT
  'CONTRACT' AS `entity_type`,
  CAST(`q_v_contract_list`.`IDcon` AS UNSIGNED) AS `entity_id`,
  LEFT(CONCAT('Договор #', CAST(`q_v_contract_list`.`IDcon` AS char CHARSET utf8)), 255) AS `title`,
  LEFT(CONCAT_WS(' | ', CONVERT(DATE_FORMAT(`q_v_contract_list`.`conDate`, '%Y-%m-%d') USING utf8mb4), `q_v_contract_list`.`conStatus`), 255) AS `subtitle`,
  UPPER(TRIM(CONCAT_WS(' ', CONVERT(CAST(`q_v_contract_list`.`IDcon` AS char CHARSET utf8) USING utf8mb4), CONVERT(DATE_FORMAT(`q_v_contract_list`.`conDate`, '%Y-%m-%d') USING utf8mb4), `q_v_contract_list`.`conStatus`))) AS `search_text`
FROM `q_v_contract_list`
UNION ALL
SELECT
  'CLIENT' AS `entity_type`,
  CAST(`client`.`IDcl` AS UNSIGNED) AS `entity_id`,
  LEFT(`client`.`clFIO`, 255) AS `title`,
  LEFT(CONCAT_WS(' | ', `client`.`clPhone`, `client`.`clEmail`), 255) AS `subtitle`,
  UPPER(TRIM(CONCAT_WS(' ', `client`.`clFIO`, `client`.`clPhone`, `client`.`clEmail`, `client`.`clPassport`, `client`.`clAddress`, `client`.`clNote`))) AS `search_text`
FROM `client`
UNION ALL
SELECT
  'EMPLOYEE' AS `entity_type`,
  CAST(`e`.`IDemp` AS UNSIGNED) AS `entity_id`,
  LEFT(`e`.`empFIO`, 255) AS `title`,
  LEFT(CONCAT_WS(' | ', `ep`.`epName`, `e`.`empPhone`, `e`.`empEmail`), 255) AS `subtitle`,
  UPPER(TRIM(CONCAT_WS(' ', `e`.`empFIO`, `ep`.`epName`, `e`.`empPhone`, `e`.`empEmail`))) AS `search_text`
FROM (`employee` `e`
  LEFT JOIN `employee_position` `ep`
    ON ((`ep`.`IDep` = `e`.`empPositionID`)))
UNION ALL
SELECT
  'SETTLEMENT' AS `entity_type`,
  CAST(`snt_settlement`.`IDsns` AS UNSIGNED) AS `entity_id`,
  LEFT(`snt_settlement`.`snsName`, 255) AS `title`,
  LEFT(CONCAT_WS(' | ', `snt_settlement`.`snsDistrict`, `snt_settlement`.`snsRegion`), 255) AS `subtitle`,
  UPPER(TRIM(CONCAT_WS(' ', `snt_settlement`.`snsName`, `snt_settlement`.`snsDistrict`, `snt_settlement`.`snsRegion`))) AS `search_text`
FROM `snt_settlement`
UNION ALL
SELECT
  'PLACE' AS `entity_type`,
  CAST(`snt_place`.`IDsp` AS UNSIGNED) AS `entity_id`,
  LEFT(`snt_place`.`spAddress`, 255) AS `title`,
  LEFT(CONCAT_WS(' | ', `snt_place`.`spStreet`, `snt_place`.`spPlotNo`, `snt_place`.`spHouseNo`, `snt_place`.`spCadastral`), 255) AS `subtitle`,
  UPPER(TRIM(CONCAT_WS(' ', `snt_place`.`spAddress`, `snt_place`.`spStreet`, `snt_place`.`spPlotNo`, `snt_place`.`spHouseNo`, `snt_place`.`spCadastral`))) AS `search_text`
FROM `snt_place`
UNION ALL
SELECT
  'MATERIAL_TYPE' AS `entity_type`,
  CAST(`material_type`.`IDmt` AS UNSIGNED) AS `entity_id`,
  LEFT(`material_type`.`mtName`, 255) AS `title`,
  '' AS `subtitle`,
  UPPER(TRIM(CONCAT_WS(' ', `material_type`.`mtName`))) AS `search_text`
FROM `material_type`
UNION ALL
SELECT
  'UTILITY_TYPE' AS `entity_type`,
  CAST(`utility_type`.`IDut` AS UNSIGNED) AS `entity_id`,
  LEFT(`utility_type`.`utName`, 255) AS `title`,
  LEFT(`utility_type`.`utUnit`, 255) AS `subtitle`,
  UPPER(TRIM(CONCAT_WS(' ', `utility_type`.`utName`, `utility_type`.`utUnit`))) AS `search_text`
FROM `utility_type`
UNION ALL
SELECT
  'CHAR_TYPE' AS `entity_type`,
  CAST(`characteristic_type`.`IDct` AS UNSIGNED) AS `entity_id`,
  LEFT(`characteristic_type`.`ctName`, 255) AS `title`,
  '' AS `subtitle`,
  UPPER(TRIM(CONCAT_WS(' ', `characteristic_type`.`ctName`))) AS `search_text`
FROM `characteristic_type`;

DELIMITER $$

CREATE
PROCEDURE sp_global_search (IN p_q varchar(255), IN p_limit int)
BEGIN
  DECLARE vq varchar(255);
  DECLARE vlimit int;

  IF p_q IS NULL THEN
    SET vq = '';
  ELSE
    SET vq = UPPER(TRIM(p_q));
  END IF;

  IF p_limit IS NULL
    OR p_limit < 1 THEN
    SET vlimit = 500;
  ELSE
    SET vlimit = p_limit;
  END IF;

  SELECT
    entity_type,
    entity_id,
    title,
    subtitle
  FROM q_v_global_search
  WHERE (vq = ''
  OR search_text LIKE CONCAT('%', vq, '%'))
  ORDER BY entity_type, title
  LIMIT vlimit;
END
$$

DELIMITER ;

