  ocValueNum decimal(12, 2) DEFAULT NULL COMMENT 'Числовое значение',
  ocValueText varchar(255) DEFAULT NULL COMMENT 'Текстовое значение',
  ocValueBool tinyint(1) DEFAULT NULL COMMENT 'Логическое значение (1/0)',
