USE kairos_realty;

DROP TRIGGER IF EXISTS trg_contract_bi_one_active;

DROP TRIGGER IF EXISTS trg_contract_bu_one_active;

DROP TRIGGER IF EXISTS trg_object_bi_code;

DROP TRIGGER IF EXISTS trg_object_bu_validate_sold;

USE kairos_realty;

DELIMITER $$

CREATE
TRIGGER trg_object_bu_validate_sold
BEFORE UPDATE
ON object
FOR EACH ROW
BEGIN
  DECLARE v_sold_obj int DEFAULT NULL;
  DECLARE v_closed_con int DEFAULT NULL;
  DECLARE v_cnt_closed int DEFAULT 0;

  SELECT
    IDos INTO v_sold_obj
  FROM object_status
  WHERE osName = 'Продан'
  LIMIT 1;

  SELECT
    IDcs INTO v_closed_con
  FROM contract_status
  WHERE csName = 'Closed'
  LIMIT 1;

  IF v_sold_obj IS NULL
    OR v_closed_con IS NULL THEN
    SIGNAL SQLSTATE '45000'
    SET MESSAGE_TEXT = 'Не найдены обязательные статусы для проверки продажи.';
  END IF;

  IF NEW.obStatusID = v_sold_obj
    AND OLD.obStatusID <> v_sold_obj THEN
    SELECT
      COUNT(*) INTO v_cnt_closed
    FROM contract
    WHERE conObjectID = OLD.IDob
    AND conStatusID = v_closed_con;

    IF v_cnt_closed = 0 THEN
      SIGNAL SQLSTATE '45000'
      SET MESSAGE_TEXT = 'Нельзя поставить объект "Продан": отсутствует договор со статусом Closed по этому объекту.';
    END IF;
  END IF;
END
$$

CREATE
TRIGGER trg_object_bi_code
BEFORE INSERT
ON object
FOR EACH ROW
BEGIN
  DECLARE v_next int;

  IF NEW.obCode IS NULL
    OR NEW.obCode = '' THEN

    SELECT
      IFNULL(MAX(CAST(SUBSTRING(obCode, 4) AS UNSIGNED)), 0) + 1 INTO v_next
    FROM object
    WHERE obCode LIKE 'KH-%';

    SET NEW.obCode = CONCAT('KH-', LPAD(v_next, 4, '0'));
  END IF;
END
$$

CREATE
TRIGGER trg_contract_bu_one_active
BEFORE UPDATE
ON contract
FOR EACH ROW
BEGIN
  DECLARE v_active_con int DEFAULT NULL;
  DECLARE v_cnt int DEFAULT 0;

  SELECT
    IDcs INTO v_active_con
  FROM contract_status
  WHERE csName = 'Active'
  LIMIT 1;

  IF v_active_con IS NULL THEN
    SIGNAL SQLSTATE '45000'
    SET MESSAGE_TEXT = 'Не найден статус договора Active.';
  END IF;

  IF NEW.conStatusID = v_active_con THEN
    SELECT
      COUNT(*) INTO v_cnt
    FROM contract
    WHERE conObjectID = NEW.conObjectID
    AND conStatusID = v_active_con
    AND IDcon <> OLD.IDcon;

    IF v_cnt > 0 THEN
      SIGNAL SQLSTATE '45000'
      SET MESSAGE_TEXT = 'Нельзя установить статус Active: по объекту уже есть другой Active-договор.';
    END IF;
  END IF;
END
$$

CREATE
TRIGGER trg_contract_bi_one_active
BEFORE INSERT
ON contract
FOR EACH ROW
BEGIN
  DECLARE v_active_con int DEFAULT NULL;
  DECLARE v_cnt int DEFAULT 0;

  SELECT
    IDcs INTO v_active_con
  FROM contract_status
  WHERE csName = 'Active'
  LIMIT 1;

  IF v_active_con IS NULL THEN
    SIGNAL SQLSTATE '45000'
    SET MESSAGE_TEXT = 'Не найден статус договора Active.';
  END IF;

  IF NEW.conStatusID = v_active_con THEN
    SELECT
      COUNT(*) INTO v_cnt
    FROM contract
    WHERE conObjectID = NEW.conObjectID
    AND conStatusID = v_active_con;

    IF v_cnt > 0 THEN
      SIGNAL SQLSTATE '45000'
      SET MESSAGE_TEXT = 'Нельзя создать второй договор со статусом Active для одного объекта.';
    END IF;
  END IF;
END
$$

DELIMITER ;

/*!40101 SET SQL_MODE=@OLD_SQL_MODE */;

/*!40014 SET FOREIGN_KEY_CHECKS = @OLD_FOREIGN_KEY_CHECKS */;

